testbench:
`timescale 1ns/1ps
module tb;
  reg [7:0] in;
  wire [7:0] out;
  integer i;

  vector_rev8 dut(.in(in), .out(out));

  function [7:0] reverse8;
    input [7:0] value;
    integer idx;
    begin
      for (idx = 0; idx < 8; idx = idx + 1) begin
        reverse8[idx] = value[7-idx];
      end
    end
  endfunction

  initial begin
    for (i = 0; i < 256; i = i + 1) begin
      in = i[7:0];
      #1;
      if (out !== reverse8(i[7:0])) begin
        $display("FAIL in=%0h expected=%0h got=%0h", in, reverse8(i[7:0]), out);
        $fatal(1);
      end
    end
    $display("PASS");
    $finish;
  end
endmodule

reference_rtl:
module vector_rev8(input [7:0] in, output [7:0] out);
  assign out = {in[0], in[1], in[2], in[3], in[4], in[5], in[6], in[7]};
endmodule
